set -e; d=$(mktemp -d); git clone -q --depth 1 -b fix/telegram-reply-formatting https://github.com/blueman82/assistant-agent.git "$d"; cd "$d"; cat > bridge/__eval_e1.ts <<'PROBE'
import assert from "node:assert/strict";
import { sendChunked } from "./api.ts";
const sent: string[] = [];
const transport = (async (_url: unknown, init: { body?: unknown }) => {
  const body = JSON.parse(String(init.body));
  if (typeof body.text === "string") sent.push(body.text);
  return { ok: true, json: async () => ({ ok: true, result: {} }) } as Response;
}) as unknown as typeof fetch;
await sendChunked({ token: "t", chatId: "1", transport }, "## Plan\n**Bold move** with *italic aside* and __underlined__ plus `inline code` and [the docs](https://example.com/page)");
const out = sent.join("");
assert.ok(!/[*_#`]|\]\(/.test(out), "markdown tokens leaked: " + JSON.stringify(out));
for (const s of ["Plan", "Bold move", "italic aside", "underlined", "inline code", "the docs", "https://example.com/page"]) {
  assert.ok(out.includes(s), "content lost: " + s + " :: " + JSON.stringify(out));
}
console.log("E1 PASS");
PROBE
node --experimental-strip-types bridge/__eval_e1.ts

